head.b:skin:
/* ==========================================================================
   CloudScript Pro Theme
   본문 콘텐츠에 최적화된 경량 · 반응형 · SEO 우선 블로그 테마
   ========================================================================== */

:root{
  --cp-bg:#ffffff;
  --cp-bg-alt:#f7f8fa;
  --cp-surface:#ffffff;
  --cp-border:#e6e8eb;
  --cp-border-strong:#d7dade;
  --cp-text:#1d2129;
  --cp-text-sub:#5b6472;
  --cp-text-faint:#8a919c;
  --cp-accent:#2457c5;
  --cp-accent-dark:#173d94;
  --cp-accent-soft:#eaf0fd;
  --cp-accent-contrast:#ffffff;
  --cp-radius-sm:6px;
  --cp-radius-md:10px;
  --cp-radius-lg:16px;
  --cp-shadow-sm:0 1px 3px rgba(20,24,34,.06),0 1px 2px rgba(20,24,34,.04);
  --cp-shadow-md:0 6px 20px rgba(20,24,34,.08);
  --cp-maxw:1180px;
  --cp-content-maxw:760px;
  --cp-font-base:'Noto Sans KR',-apple-system,BlinkMacSystemFont,'Malgun Gothic',sans-serif;
  --cp-font-serif:'Noto Serif KR',serif;
}

*,*::before,*::after{box-sizing:border-box;}
html{-webkit-text-size-adjust:100%;text-size-adjust:100%;scroll-behavior:smooth;}
body{
  margin:0;
  background:var(--cp-bg-alt);
  color:var(--cp-text);
  font-family:var(--cp-font-base);
  font-size:16px;
  line-height:1.75;
  word-break:keep-all;
  -webkit-font-smoothing:antialiased;
  overflow-x:hidden;
}
body.cp-scroll-lock{position:fixed;top:0;left:0;right:0;width:100%;overflow:hidden;}
img{max-width:100%;height:auto;display:block;border-style:none;}
svg{max-width:100%;}
a{color:var(--cp-accent);text-decoration:none;}
a:hover{text-decoration:underline;}
ul,ol{padding-inline-start:1.4em;}
figure{margin:0;}
button{font-family:inherit;}
.cp-container{max-width:var(--cp-maxw);margin:0 auto;padding:0 20px;}
.cp-visually-hidden{position:absolute!important;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0;}
/* JS 로딩 여부와 무관하게 콘텐츠가 항상 보이도록 안전하게 처리.
   loading 클래스는 시각적 초기 깜빡임 방지용 보조 장치일 뿐,
   JS 실패 시에도 0.4초 후 CSS 애니메이션으로 자동 노출됨 (에러로 인한 콘텐츠 미노출 방지) */
.cp-fade{animation:cpFadeIn .3s ease .05s both;}
html.loading .cp-fade{opacity:0;animation:cpFadeIn .3s ease .4s both;}
@keyframes cpFadeIn{from{opacity:.4;}to{opacity:1;}}
@media (prefers-reduced-motion:reduce){.cp-fade{animation:none;opacity:1;}html.loading .cp-fade{opacity:1;}}

/* ==========================================================================
   레이아웃 뼈대
   ========================================================================== */
.cp-shell{display:flex;flex-direction:column;min-height:100vh;}
.cp-main-wrap{flex:1 0 auto;}
.cp-body-grid{
  display:grid;
  grid-template-columns:minmax(0,1fr) 320px;
  gap:32px;
  max-width:var(--cp-maxw);
  margin:0 auto;
  padding:28px 20px 60px;
  align-items:start;
}
.cp-main-col{min-width:0;align-self:start;}
.cp-side-col{min-width:0;position:sticky;top:88px;align-self:start;}
@media (max-width:980px){
  .cp-body-grid{grid-template-columns:1fr;padding:18px 16px 44px;gap:0;}
  .cp-side-col{position:static;margin-top:28px;}
}

/* ==========================================================================
   헤더
   ========================================================================== */
.cp-header{
  background:var(--cp-surface);
  border-bottom:1px solid var(--cp-border);
  position:sticky;top:0;z-index:60;
}
.cp-header-inner{
  max-width:var(--cp-maxw);margin:0 auto;padding:0 20px;
  display:flex;align-items:center;gap:20px;height:68px;
}
.cp-brand{display:flex;align-items:center;gap:10px;margin-right:auto;min-width:0;}
.cp-brand-logo-img{height:36px;width:auto;border-radius:6px;}
.cp-brand-text{display:flex;flex-direction:column;min-width:0;}
.cp-brand-title{
  font-size:20px;font-weight:900;color:var(--cp-text);letter-spacing:-.02em;
  white-space:nowrap;overflow:hidden;text-overflow:ellipsis;
}
.cp-brand-title:hover{text-decoration:none;}
.cp-brand-desc{font-size:12px;color:var(--cp-text-faint);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}

.cp-nav{display:flex;align-items:center;}
.cp-nav ul{list-style:none;margin:0;padding:0;display:flex;gap:2px;}
.cp-nav li{position:relative;}
.cp-nav a{
  display:flex;align-items:center;height:68px;padding:0 14px;
  font-size:14.5px;font-weight:700;color:var(--cp-text);white-space:nowrap;
}
.cp-nav a:hover{color:var(--cp-accent);text-decoration:none;}
.cp-nav li.cp-has-sub:hover > .cp-sub-menu{opacity:1;visibility:visible;transform:translateY(0);}
.cp-sub-menu{
  position:absolute;top:100%;left:0;min-width:200px;background:var(--cp-surface);
  border:1px solid var(--cp-border);border-radius:var(--cp-radius-md);box-shadow:var(--cp-shadow-md);
  list-style:none;margin:6px 0 0;padding:8px;opacity:0;visibility:hidden;transform:translateY(6px);
  transition:.18s ease;z-index:80;
}
.cp-sub-menu a{height:auto;padding:9px 12px;border-radius:8px;font-weight:500;}
.cp-sub-menu a:hover{background:var(--cp-accent-soft);}

.cp-header-tools{display:flex;align-items:center;gap:6px;}
.cp-icon-btn{
  width:38px;height:38px;border-radius:50%;border:1px solid var(--cp-border);background:var(--cp-surface);
  display:flex;align-items:center;justify-content:center;cursor:pointer;color:var(--cp-text);flex-shrink:0;
}
.cp-icon-btn:hover{background:var(--cp-accent-soft);border-color:var(--cp-accent);}
.cp-icon-btn svg{width:18px;height:18px;}
.cp-hamburger{display:none;}

.cp-search-panel{
  position:fixed;inset:0;background:rgba(20,24,34,.5);z-index:200;display:none;align-items:flex-start;justify-content:center;padding-top:12vh;
}
.cp-search-panel.cp-open{display:flex;}
.cp-search-box{background:var(--cp-surface);border-radius:var(--cp-radius-lg);width:min(560px,92vw);padding:18px;box-shadow:var(--cp-shadow-md);}
.cp-search-box form{display:flex;gap:8px;}
.cp-search-box input[type="text"]{
  flex:1;padding:12px 14px;border:1.5px solid var(--cp-border-strong);border-radius:var(--cp-radius-sm);font-size:15px;
}
.cp-search-box input[type="text"]:focus{outline:none;border-color:var(--cp-accent);}
.cp-search-submit{
  background:var(--cp-accent);color:#fff;border:none;border-radius:var(--cp-radius-sm);padding:0 18px;font-weight:700;cursor:pointer;
}
.cp-search-close{margin-top:10px;font-size:13px;color:var(--cp-text-faint);cursor:pointer;text-align:right;}

@media (max-width:980px){
  .cp-nav{
    position:fixed;top:0;right:-100%;left:auto;width:82%;max-width:340px;min-width:260px;height:100%;background:var(--cp-surface);
    flex-direction:column;align-items:flex-start;padding:70px 0 20px;transition:right .3s ease;z-index:150;overflow-y:auto;box-shadow:-6px 0 20px rgba(0,0,0,.12);
    flex-shrink:0;flex-grow:0;flex-basis:auto;box-sizing:border-box;
  }
  .cp-nav.cp-open{right:0;}
  .cp-nav .cp-nav-section{width:100%;}
  .cp-nav ul{flex-direction:column;width:100%;gap:0;box-sizing:border-box;}
  .cp-nav li{width:100%;}
  .cp-nav a{height:auto;padding:14px 24px;width:100%;box-sizing:border-box;border-bottom:1px solid var(--cp-border);text-align:left;}
  .cp-sub-menu{position:static;opacity:1;visibility:visible;transform:none;box-shadow:none;border:none;border-radius:0;background:var(--cp-bg-alt);margin:0;display:none;}
  .cp-has-sub.cp-mobile-open .cp-sub-menu{display:block;}
  .cp-hamburger{display:flex;}
  .cp-nav-overlay{position:fixed;inset:0;background:rgba(20,24,34,.45);z-index:140;display:none;}
  .cp-nav-overlay.cp-open{display:block;}
  .cp-brand-desc{display:none;}
}

/* ==========================================================================
   Breadcrumb
   ========================================================================== */
.cp-breadcrumb{max-width:var(--cp-maxw);margin:0 auto;padding:14px 20px 0;}
.cp-breadcrumb ol{list-style:none;display:flex;flex-wrap:wrap;gap:4px;margin:0;padding:0;font-size:12.5px;color:var(--cp-text-faint);}
.cp-breadcrumb li{display:flex;align-items:center;gap:4px;}
.cp-breadcrumb li:not(:last-child)::after{content:'/';margin-left:4px;color:var(--cp-border-strong);}
.cp-breadcrumb a{color:var(--cp-text-faint);}
.cp-breadcrumb a:hover{color:var(--cp-accent);}



/* ==========================================================================
   포스트 카드 (인덱스 / 검색 / 라벨 리스트)
   ========================================================================== */
.cp-post-list{display:flex;flex-direction:column;gap:20px;}
.cp-post-card{
  background:var(--cp-surface);border:1px solid var(--cp-border);border-radius:var(--cp-radius-lg);
  overflow:hidden;display:flex;gap:20px;padding:16px;transition:.2s ease;
}
.cp-post-card:hover{border-color:var(--cp-border-strong);box-shadow:var(--cp-shadow-sm);}
.cp-post-card-thumb{
  flex:0 0 240px;height:150px;border-radius:var(--cp-radius-md);overflow:hidden;background:var(--cp-bg-alt);
}
.cp-post-card-thumb img{width:100%;height:100%;object-fit:cover;}
.cp-auto-thumb{background-color:var(--cp-bg-alt);background-size:cover;background-position:center;opacity:0;transition:opacity .25s ease;}
.cp-auto-thumb.cp-thumb-ready{opacity:1;}
.cp-post-card-body{flex:1;min-width:0;display:flex;flex-direction:column;}
.cp-post-card-cat{font-size:12px;font-weight:800;color:var(--cp-accent);margin-bottom:6px;}
.cp-post-card-title{font-size:19px;font-weight:800;line-height:1.4;color:var(--cp-text);margin:0 0 8px;letter-spacing:-.01em;}
.cp-post-card-title a{color:inherit;}
.cp-post-card-title a:hover{text-decoration:none;color:var(--cp-accent);}
.cp-post-card-snippet{font-size:14px;color:var(--cp-text-sub);line-height:1.7;margin:0 0 10px;
  display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;}
.cp-post-card-meta{margin-top:auto;display:flex;align-items:center;gap:10px;font-size:12.5px;color:var(--cp-text-faint);}
.cp-post-card-meta span{display:flex;align-items:center;gap:4px;}
@media (max-width:640px){
  .cp-post-card{flex-direction:column;}
  .cp-post-card-thumb{flex:none;width:100%;height:200px;}
}

.cp-pagination{display:flex;justify-content:center;gap:8px;margin-top:32px;}
.cp-pagination a,.cp-pagination span{
  min-width:40px;height:40px;padding:0 10px;border-radius:var(--cp-radius-sm);border:1px solid var(--cp-border);
  display:flex;align-items:center;justify-content:center;font-weight:700;font-size:14px;color:var(--cp-text);background:var(--cp-surface);
}
.cp-pagination a:hover{border-color:var(--cp-accent);color:var(--cp-accent);text-decoration:none;}
.cp-pagination-disabled{opacity:.4;cursor:not-allowed;}

/* ==========================================================================
   개별 포스트 아티클
   ========================================================================== */
.cp-article{background:var(--cp-surface);border:1px solid var(--cp-border);border-radius:var(--cp-radius-lg);padding:32px;}
@media (max-width:640px){.cp-article{padding:20px 16px;border-radius:var(--cp-radius-md);}}

.cp-article-cat a{
  display:inline-block;font-size:12.5px;font-weight:800;color:var(--cp-accent);background:var(--cp-accent-soft);
  padding:4px 10px;border-radius:20px;margin-bottom:14px;
}
.cp-article-title{font-size:clamp(24px,4vw,34px);font-weight:900;line-height:1.42;letter-spacing:-.02em;margin:0 0 16px;color:var(--cp-text);}
.cp-article-meta{display:flex;flex-wrap:wrap;align-items:center;gap:14px;font-size:13.5px;color:var(--cp-text-faint);
  padding-bottom:20px;margin-bottom:24px;border-bottom:1px solid var(--cp-border);}
.cp-article-meta .cp-author{display:flex;align-items:center;gap:8px;color:var(--cp-text-sub);font-weight:700;}
.cp-author-avatar{width:26px;height:26px;border-radius:50%;background:var(--cp-accent-soft);color:var(--cp-accent);
  display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:800;overflow:hidden;}
.cp-author-avatar img{width:100%;height:100%;object-fit:cover;}

.cp-article-thumb{border-radius:var(--cp-radius-md);overflow:hidden;margin-bottom:26px;background:var(--cp-bg-alt);aspect-ratio:16/9;}
.cp-article-thumb img{width:100%;height:100%;object-fit:cover;}
.cp-auto-thumb-lg{background-size:cover;background-position:center;}

/* ---- 본문 타이포그래피 ---- */
.cp-post-body{font-size:16.5px;line-height:1.9;color:var(--cp-text);max-width:100%;overflow-x:hidden;}
.cp-post-body > *:first-child{margin-top:0;}
.cp-post-body p{margin:0 0 22px;}
/* 본문 안의 모든 요소가 컨테이너 폭을 넘지 않도록 안전장치 */
.cp-post-body img,.cp-post-body video,.cp-post-body iframe,.cp-post-body embed,.cp-post-body object{
  max-width:100%;height:auto;
}
.cp-post-body h2,.cp-post-body h3,.cp-post-body h4{
  font-family:'Pretendard','Apple SD Gothic Neo','Malgun Gothic',sans-serif;font-weight:800;letter-spacing:0;color:#222;
  scroll-margin-top:90px;position:relative;word-break:keep-all;
}
.cp-post-body h2{display:flex;align-items:center;gap:10px;font-size:21px;margin:24px 0 14px;padding-bottom:10px;border-bottom:3px solid #222;}
.cp-post-body h3{font-size:21px;margin:24px 0 14px;padding-bottom:10px;border-bottom:3px solid #222;padding-left:0;border-left:0;}
.cp-post-body h4{font-size:18px;margin:24px 0 12px;color:#222;}
.cp-post-body h2:first-child,.cp-post-body h3:first-child{margin-top:0;}
/* class가 붙은 링크(사용자가 삽입한 버튼/카드형 위젯 등)는 테마 기본 링크 밑줄에서 제외해
   본문에 붙여넣는 커스텀 스니펫의 버튼 디자인이 항상 우선 적용되도록 한다. */
.cp-post-body a:not([class]){color:var(--cp-accent);text-decoration:underline;text-decoration-color:var(--cp-accent-soft);text-underline-offset:3px;}
.cp-post-body a:not([class]):hover{text-decoration-color:var(--cp-accent);}
.cp-post-body strong{font-weight:800;}
.cp-post-body ul li,.cp-post-body ol li{margin-bottom:8px;}
.cp-post-body blockquote{
  margin:24px 0;padding:16px 20px;background:var(--cp-bg-alt);border-left:4px solid var(--cp-accent);
  border-radius:0 var(--cp-radius-sm) var(--cp-radius-sm) 0;color:var(--cp-text-sub);font-size:15.5px;
}
.cp-post-body blockquote p:last-child{margin-bottom:0;}
.cp-post-body hr{border:none;border-top:1px solid var(--cp-border);margin:36px 0;}
.cp-post-body code{
  background:var(--cp-bg-alt);border:1px solid var(--cp-border);padding:2px 6px;border-radius:4px;
  font-size:.9em;font-family:'SFMono-Regular',Consolas,monospace;
  word-break:break-word;
}
.cp-post-body pre{
  background:#1d2129;color:#e8eaed;padding:18px;border-radius:var(--cp-radius-md);overflow-x:auto;margin:24px 0;font-size:14px;line-height:1.7;
  max-width:100%;
}
.cp-post-body pre code{background:none;border:none;color:inherit;padding:0;}
.cp-post-body figure{margin:26px 0;max-width:100%;}
.cp-post-body figure img{border-radius:var(--cp-radius-md);width:100%;}
.cp-post-body figcaption{text-align:center;font-size:13px;color:var(--cp-text-faint);margin-top:8px;}

/* ---- 표: 래퍼 유무와 무관하게 항상 컨테이너 폭 안에서 가로 스크롤되도록 처리 ----
   주의: class 속성이 있는 <table>(직접 삽입한 위젯/스니펫용 테이블 등)은
   테마의 강제 표 스타일에서 제외한다. 그래야 사용자가 본문에 붙여넣는
   자체 디자인 테이블(class="xxxx-table" 형태)이 테마 기본 표 스타일과
   충돌하지 않는다. */
.cp-post-body .cp-table-wrap{overflow-x:auto;margin:24px 0;border-radius:8px;border:1px solid #e0ddd4;max-width:100%;-webkit-overflow-scrolling:touch;}
.cp-post-body table:not([class]){
  width:auto;
  max-width:100%;
  overflow-x:auto;
  -webkit-overflow-scrolling:touch;
  border-collapse:collapse;
  border:1px solid #e0ddd4;
  border-radius:8px;
  background:#fff;
  margin:24px 0;
}
.cp-post-body .cp-table-wrap table:not([class]){margin:0;border:none;border-radius:0;}
.cp-post-body table:not([class]) thead,.cp-post-body table:not([class]) tbody{display:table;width:auto;max-width:100%;table-layout:auto;}
.cp-post-body table:not([class]) thead th,.cp-post-body table:not([class]) th{background:#f5f0e4;color:#333;font-size:14px;font-weight:700;padding:14px 8px;border:1px solid #e8e4d8;text-align:center;line-height:1.5;}
.cp-post-body table:not([class]) td{padding:16px 8px;border:1px solid #eeebe2;text-align:center;font-size:14px;color:#333;line-height:1.6;background:#fcfbf7;word-break:keep-all;}

/* 사용자가 직접 삽입한 커스텀 위젯(class가 붙은 table)은 가로 스크롤만 보장하고
   나머지 디자인은 위젯 자체 CSS를 그대로 따르도록 최소한만 개입한다. */
.cp-post-body table[class]{max-width:100%;overflow-x:auto;-webkit-overflow-scrolling:touch;}

/* ---- 테마 고유 버튼: 본문 중 "굵은 링크" 자동 버튼화 ---- */
.cp-post-body p > a.cp-cta-btn,.cp-post-body p > b > a.cp-cta-btn,.cp-post-body p > strong > a.cp-cta-btn{
  display:inline-block;background:#fdf3ee;color:#b3261e!important;font-size:14px;font-weight:800;letter-spacing:.3px;padding:7px 16px;border:1.5px solid #b3261e;border-radius:8px;box-shadow:0 2px 0 #b3261e;cursor:pointer;user-select:all;transition:transform .08s,box-shadow .08s;font-family:inherit;text-decoration:none!important;margin:6px 0;
}
.cp-post-body a.cp-cta-btn:hover{text-decoration:none;background:#fdf3ee;color:#b3261e!important;}
.cp-post-body a.cp-cta-btn:active{transform:translateY(2px);box-shadow:0 0 0 #b3261e;}
.cp-post-body a.cp-cta-btn::after{content:none;}
.cp-cta-btn-wrap{text-align:center;margin:30px 0;}
.cp-cta-btn-wrap a.cp-cta-btn{margin:0;}
@media (max-width:520px){
.cp-post-body table:not([class]) th,.cp-post-body table:not([class]) td{font-size:12.5px;padding:12px 4px}
.cp-post-body p > a.cp-cta-btn,.cp-post-body p > b > a.cp-cta-btn,.cp-post-body p > strong > a.cp-cta-btn{font-size:12.5px;padding:6px 10px}
.cp-post-body h2,.cp-post-body h3{font-size:18px}
}

/* ---- 자동 목차 (TOC) ---- */
.cp-toc{
  background:var(--cp-bg-alt);border:1px solid var(--cp-border);border-radius:var(--cp-radius-md);
  padding:18px 20px;margin:0 0 30px;
}
.cp-toc-head{display:flex;align-items:center;justify-content:space-between;cursor:pointer;user-select:none;}
.cp-toc-title{font-size:15px;font-weight:800;display:flex;align-items:center;gap:8px;}
.cp-toc-title svg{width:17px;height:17px;color:var(--cp-accent);}
.cp-toc-toggle{width:22px;height:22px;display:flex;align-items:center;justify-content:center;transition:transform .2s ease;color:var(--cp-text-faint);}
.cp-toc.cp-collapsed .cp-toc-toggle{transform:rotate(-90deg);}
.cp-toc-list{list-style:none;margin:14px 0 0;padding:0;max-height:1000px;overflow:hidden;transition:max-height .25s ease,margin .25s ease,opacity .2s ease;}
.cp-toc.cp-collapsed .cp-toc-list{max-height:0;margin-top:0;opacity:0;}
.cp-toc-list li{margin:0;padding:8px 0;border-top:1px dashed var(--cp-border);font-size:14px;}
.cp-toc-list li:first-child{border-top:none;}
.cp-toc-list a{color:var(--cp-text-sub);font-weight:600;}
.cp-toc-list a:hover{color:var(--cp-accent);text-decoration:none;}
.cp-toc-list .cp-toc-lv3{padding-left:16px;font-weight:400;font-size:13.5px;}

/* ---- 태그/공유/이전다음 ---- */
.cp-post-tags{display:flex;flex-wrap:wrap;gap:8px;margin:34px 0 0;}
.cp-post-tags a{
  font-size:13px;color:var(--cp-text-sub);background:var(--cp-bg-alt);border:1px solid var(--cp-border);
  padding:6px 13px;border-radius:20px;
}
.cp-post-tags a:hover{border-color:var(--cp-accent);color:var(--cp-accent);text-decoration:none;}

.cp-share-row{display:flex;align-items:center;justify-content:space-between;gap:14px;margin:28px 0;padding:16px 0;
  border-top:1px solid var(--cp-border);border-bottom:1px solid var(--cp-border);}
.cp-share-label{font-size:14px;font-weight:700;color:var(--cp-text-sub);}
.cp-share-btn{
  display:flex;align-items:center;gap:8px;background:var(--cp-text);color:#fff;border:none;border-radius:50px;
  padding:11px 20px;font-size:14px;font-weight:700;cursor:pointer;
}
.cp-share-btn:hover{background:var(--cp-accent-dark);}
.cp-share-btn svg{width:16px;height:16px;}
.cp-share-toast{
  position:fixed;left:50%;bottom:30px;transform:translateX(-50%) translateY(20px);background:var(--cp-text);color:#fff;
  padding:11px 22px;border-radius:50px;font-size:13.5px;font-weight:600;opacity:0;visibility:hidden;transition:.25s ease;z-index:300;
}
.cp-share-toast.cp-show{opacity:1;visibility:visible;transform:translateX(-50%) translateY(0);}

.cp-author-box{
  display:flex;gap:16px;background:var(--cp-bg-alt);border-radius:var(--cp-radius-md);padding:20px;margin:30px 0;align-items:flex-start;
}
.cp-author-box-avatar{width:56px;height:56px;border-radius:50%;flex-shrink:0;background:var(--cp-accent-soft);color:var(--cp-accent);
  display:flex;align-items:center;justify-content:center;font-weight:800;font-size:20px;overflow:hidden;}
.cp-author-box-avatar img{width:100%;height:100%;object-fit:cover;}
.cp-author-box-name{font-weight:800;font-size:15px;margin-bottom:4px;}
.cp-author-box-bio{font-size:13.5px;color:var(--cp-text-sub);line-height:1.6;}

.cp-post-nav{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin:30px 0;}
.cp-post-nav-item{
  border:1px solid var(--cp-border);border-radius:var(--cp-radius-md);padding:16px;display:flex;flex-direction:column;gap:6px;
  min-width:0;
}
.cp-post-nav-item:hover{border-color:var(--cp-accent);}
.cp-post-nav-dir{font-size:12px;color:var(--cp-text-faint);font-weight:700;}
.cp-post-nav-title{font-size:14px;font-weight:700;color:var(--cp-text);overflow:hidden;text-overflow:ellipsis;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;}
.cp-post-nav-item.cp-next{text-align:right;align-items:flex-end;}
@media (max-width:560px){.cp-post-nav{grid-template-columns:1fr;}.cp-post-nav-item.cp-next{text-align:left;align-items:flex-start;}}

/* ---- 댓글 ---- */
.cp-comments{margin:36px 0 10px;}
.cp-comment-list{list-style:none;margin:18px 0 0;padding:0;display:flex;flex-direction:column;gap:18px;}
.cp-comment{display:flex;gap:12px;}
.cp-comment-avatar{
  width:38px;height:38px;border-radius:50%;flex-shrink:0;overflow:hidden;
  background:var(--cp-accent-soft);color:var(--cp-accent);font-weight:800;
  display:flex;align-items:center;justify-content:center;
}
.cp-comment-avatar img{width:100%;height:100%;object-fit:cover;}
.cp-comment-main{min-width:0;flex:1;}
.cp-comment-meta{display:flex;align-items:baseline;gap:8px;flex-wrap:wrap;}
.cp-comment-author{font-weight:700;font-size:14px;color:var(--cp-text);}
.cp-comment-time{font-size:12px;color:var(--cp-text-faint);}
.cp-comment-body{font-size:14px;line-height:1.7;color:var(--cp-text-sub);margin-top:4px;word-break:break-word;}
.cp-comment-deleted{font-size:13px;color:var(--cp-text-faint);font-style:italic;}
.cp-comment-paging{display:flex;flex-wrap:wrap;gap:10px;align-items:center;margin-top:16px;font-size:13px;}
.cp-comment-paging a{font-weight:600;}
.cp-comment-range{color:var(--cp-text-faint);}
.cp-comment-form-wrap{margin-top:22px;}
.cp-comment-closed{font-size:13.5px;color:var(--cp-text-faint);}

/* ---- 관련 글 추천 ---- */
.cp-related{margin:44px 0 10px;}
.cp-section-title{font-size:19px;font-weight:900;margin:0 0 18px;display:flex;align-items:center;gap:8px;letter-spacing:-.01em;}
.cp-section-title svg{width:19px;height:19px;color:var(--cp-accent);}
.cp-related-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;}
.cp-related-card{border:1px solid var(--cp-border);border-radius:var(--cp-radius-md);overflow:hidden;transition:.18s ease;background:var(--cp-surface);}
.cp-related-card:hover{border-color:var(--cp-border-strong);box-shadow:var(--cp-shadow-sm);}
.cp-related-thumb{height:110px;background:var(--cp-bg-alt);overflow:hidden;}
.cp-related-thumb img{width:100%;height:100%;object-fit:cover;}
.cp-related-body{padding:12px;}
.cp-related-title{font-size:13.5px;font-weight:700;line-height:1.5;color:var(--cp-text);display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;}
.cp-related-title:hover{color:var(--cp-accent);text-decoration:none;}
@media (max-width:768px){.cp-related-grid{grid-template-columns:repeat(2,1fr);}}
@media (max-width:480px){.cp-related-grid{grid-template-columns:1fr;}}

/* ---- 댓글 ---- */
#comments{margin-top:40px;padding-top:30px;border-top:1px solid var(--cp-border);}
#comments .comments-content{font-size:14px;}



/* ==========================================================================
   사이드바 위젯 공통 카드
   ========================================================================== */
.cp-widget{background:var(--cp-surface);border:1px solid var(--cp-border);border-radius:var(--cp-radius-lg);padding:20px;margin-bottom:22px;}
.cp-widget-title{font-size:15px;font-weight:900;margin:0 0 16px;display:flex;align-items:center;gap:8px;letter-spacing:-.01em;}
.cp-widget-title svg{width:16px;height:16px;color:var(--cp-accent);}

.cp-profile-widget{text-align:center;}
.cp-profile-avatar{width:76px;height:76px;border-radius:50%;margin:0 auto 12px;overflow:hidden;background:var(--cp-accent-soft);
  display:flex;align-items:center;justify-content:center;font-size:26px;font-weight:800;color:var(--cp-accent);}
.cp-profile-avatar img{width:100%;height:100%;object-fit:cover;}
.cp-profile-name{font-size:16px;font-weight:800;margin-bottom:6px;}
.cp-profile-bio{font-size:13px;color:var(--cp-text-sub);line-height:1.6;margin-bottom:14px;}
.cp-profile-socials{display:flex;justify-content:center;gap:8px;flex-wrap:wrap;}
.cp-profile-socials a{
  width:34px;height:34px;border-radius:50%;background:var(--cp-bg-alt);display:flex;align-items:center;justify-content:center;color:var(--cp-text-sub);
}
.cp-profile-socials a:hover{background:var(--cp-accent);color:#fff;}
.cp-profile-socials svg{width:16px;height:16px;}

.cp-list-widget{list-style:none;margin:0;padding:0;}
.cp-list-widget li{border-top:1px solid var(--cp-border);}
.cp-list-widget li:first-child{border-top:none;}
.cp-mini-post{display:flex;gap:12px;padding:12px 0;align-items:center;}
.cp-mini-thumb{flex:0 0 62px;height:62px;border-radius:8px;overflow:hidden;background:var(--cp-bg-alt);}
.cp-mini-thumb img{width:100%;height:100%;object-fit:cover;}
.cp-mini-info{min-width:0;}
.cp-mini-title{font-size:13.5px;font-weight:700;line-height:1.5;color:var(--cp-text);display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;}
.cp-mini-title:hover{color:var(--cp-accent);text-decoration:none;}
.cp-mini-date{font-size:11.5px;color:var(--cp-text-faint);margin-top:4px;}
.cp-mini-rank{flex:0 0 22px;font-size:14px;font-weight:900;color:var(--cp-accent);text-align:center;}

.cp-label-cloud{display:flex;flex-wrap:wrap;gap:8px;}
.cp-label-cloud a{
  font-size:12.5px;background:var(--cp-bg-alt);border:1px solid var(--cp-border);color:var(--cp-text-sub);
  padding:6px 12px;border-radius:20px;display:flex;align-items:center;gap:5px;
}
.cp-label-cloud a:hover{border-color:var(--cp-accent);color:var(--cp-accent);text-decoration:none;}
.cp-label-cloud .cp-count{color:var(--cp-text-faint);font-size:11px;}

.cp-archive-widget ul{list-style:none;margin:0;padding:0;}
.cp-archive-widget li{border-top:1px solid var(--cp-border);}
.cp-archive-widget li:first-child{border-top:none;}
.cp-archive-widget a{
  display:flex;justify-content:space-between;padding:10px 2px;font-size:13.5px;color:var(--cp-text-sub);font-weight:600;
}
.cp-archive-widget a:hover{color:var(--cp-accent);text-decoration:none;}

.cp-search-widget form{display:flex;gap:6px;}
.cp-search-widget input[type="text"]{
  flex:1;padding:10px 12px;border:1.5px solid var(--cp-border-strong);border-radius:var(--cp-radius-sm);font-size:14px;min-width:0;
}
.cp-search-widget input[type="text"]:focus{outline:none;border-color:var(--cp-accent);}
.cp-search-widget button{background:var(--cp-accent);color:#fff;border:none;border-radius:var(--cp-radius-sm);padding:0 14px;font-weight:700;cursor:pointer;}

.cp-ad-widget{text-align:center;overflow:hidden;}
.cp-ad-widget ins{display:block;}

.cp-newsletter-widget{background:linear-gradient(135deg,var(--cp-accent),var(--cp-accent-dark));border:none;color:#fff;text-align:center;}
.cp-newsletter-widget .cp-widget-title{color:#fff;justify-content:center;}
.cp-newsletter-widget .cp-widget-title svg{color:#fff;}
.cp-newsletter-widget p{font-size:13px;opacity:.9;margin:0 0 14px;}
.cp-newsletter-widget input[type="email"]{
  width:100%;padding:11px 12px;border-radius:var(--cp-radius-sm);border:none;margin-bottom:8px;font-size:14px;
}
.cp-newsletter-widget button{
  width:100%;padding:11px;border-radius:var(--cp-radius-sm);border:none;background:#fff;color:var(--cp-accent-dark);font-weight:800;cursor:pointer;
}

.cp-html-widget img{border-radius:var(--cp-radius-md);}

.cp-sticky-ad-mobile{display:none;}
@media (max-width:768px){
  .cp-sticky-ad-mobile{
    display:block;position:fixed;left:0;right:0;bottom:0;z-index:120;background:var(--cp-surface);
    border-top:1px solid var(--cp-border);padding:6px;text-align:center;
  }
  .cp-sticky-ad-close{position:absolute;top:-14px;right:8px;width:26px;height:26px;border-radius:50%;background:var(--cp-text);
    color:#fff;display:flex;align-items:center;justify-content:center;font-size:14px;cursor:pointer;}
}

/* ==========================================================================
   FAQ / 아코디언 (게시물 본문 내 위젯형 요소 및 페이지)
   ========================================================================== */
.cp-faq{margin:26px 0;}
.cp-faq-item{border:1px solid var(--cp-border);border-radius:var(--cp-radius-md);margin-bottom:10px;overflow:hidden;}
.cp-faq-q{
  display:flex;justify-content:space-between;align-items:center;gap:12px;padding:15px 18px;cursor:pointer;font-weight:700;font-size:14.5px;
  background:var(--cp-bg-alt);
}
.cp-faq-q .cp-faq-icon{flex-shrink:0;transition:transform .2s ease;color:var(--cp-accent);}
.cp-faq-item.cp-open .cp-faq-icon{transform:rotate(45deg);}
.cp-faq-a{max-height:0;overflow:hidden;transition:max-height .25s ease;font-size:14px;color:var(--cp-text-sub);line-height:1.8;}
.cp-faq-item.cp-open .cp-faq-a{max-height:600px;}
.cp-faq-a-inner{padding:15px 18px;}

/* ==========================================================================
   상단 이동, 목차 플로팅 (모바일)
   ========================================================================== */
.cp-back-to-top{
  position:fixed;right:20px;bottom:20px;width:46px;height:46px;border-radius:50%;background:var(--cp-text);color:#fff;
  display:flex;align-items:center;justify-content:center;box-shadow:var(--cp-shadow-md);cursor:pointer;opacity:0;visibility:hidden;
  transform:translateY(10px);transition:.25s ease;z-index:90;border:none;
}
.cp-back-to-top.cp-show{opacity:1;visibility:visible;transform:translateY(0);}
.cp-back-to-top svg{width:20px;height:20px;}

/* ==========================================================================
   푸터
   ========================================================================== */
.cp-footer{background:var(--cp-text);color:#c6cad2;margin-top:40px;}
.cp-footer-inner{max-width:var(--cp-maxw);margin:0 auto;padding:44px 20px;display:grid;grid-template-columns:1.4fr 1fr 1fr 1fr;gap:30px;}
.cp-footer-col-title{color:#fff;font-size:14.5px;font-weight:800;margin:0 0 14px;}
.cp-footer-brand-desc{font-size:13px;line-height:1.8;color:#9aa0ab;}
.cp-footer ul{list-style:none;margin:0;padding:0;}
.cp-footer li{margin-bottom:9px;}
.cp-footer a{color:#c6cad2;font-size:13px;}
.cp-footer a:hover{color:#fff;text-decoration:none;}
.cp-footer-bottom{border-top:1px solid #383e4a;padding:18px 20px;text-align:center;font-size:12.5px;color:#8890a0;}
.cp-footer-bottom a{color:#8890a0;}
@media (max-width:860px){
  .cp-footer-inner{grid-template-columns:1fr 1fr;}
}
@media (max-width:520px){
  .cp-footer-inner{grid-template-columns:1fr;padding:34px 18px;}
}

/* ==========================================================================
   에러/빈 상태 & 접근성 & 인쇄
   ========================================================================== */
.cp-empty-state{text-align:center;padding:70px 20px;}
.cp-empty-state svg{width:56px;height:56px;color:var(--cp-border-strong);margin-bottom:16px;}
.cp-empty-state h2{font-size:19px;margin:0 0 8px;}
.cp-empty-state p{color:var(--cp-text-sub);font-size:14px;}

.cp-page-header{max-width:var(--cp-maxw);margin:0 auto;padding:30px 20px 6px;}
.cp-page-header h1{font-size:24px;font-weight:900;margin:0;}
.cp-page-header p{color:var(--cp-text-sub);font-size:14px;margin:6px 0 0;}

a:focus-visible,button:focus-visible,input:focus-visible{outline:2.5px solid var(--cp-accent);outline-offset:2px;}

@media print{
  .cp-header,.cp-footer,.cp-side-col,.cp-share-row,.cp-back-to-top,.cp-post-nav,.cp-related,#comments,.cp-sticky-ad-mobile{display:none!important;}
}

body.script:
//
(function(){
  'use strict';

  function initFirstCardPriority(){
    var firstCard = document.querySelector('.cp-post-list .cp-post-card');
    if(!firstCard) return;
    var img = firstCard.querySelector('.cp-post-card-thumb img');
    if(!img) return;
    img.removeAttribute('loading');
    img.setAttribute('fetchpriority', 'high');
    img.setAttribute('decoding', 'async');
  }

  document.addEventListener('DOMContentLoaded', function(){
    safeRun(initFirstCardPriority);
    safeRun(initNav);
    safeRun(initSearchPanel);
    safeRun(initAutoThumbnails);
    safeRun(initAutoCtaButtons);
    safeRun(initAutoTOC);
    safeRun(initFaqAccordion);
    safeRun(initShareButton);
    safeRun(initBackToTop);
    safeRun(initStickyAdClose);
    safeRun(initRelatedPosts);
    safeRun(initRecentPosts);
    safeRun(initPopularPostsFallback);
    safeRun(initCopyrightYear);
    safeRun(function(){ document.documentElement.classList.remove('loading'); });
  });

  function safeRun(fn){
    try{ fn(); }catch(err){
      try{ document.documentElement.classList.remove('loading'); }catch(e2){}
    }
  }

  function initCopyrightYear(){
    var el = document.getElementById('cp-copyright-year');
    if(el){ el.textContent = new Date().getFullYear(); }
  }

  /* ---------------------------------------------------------
     1. 모바일 메뉴 / 오버레이
  --------------------------------------------------------- */
  function initNav(){
    var btn = document.getElementById('cp-hamburger-btn');
    var nav = document.getElementById('cp-main-nav');
    var overlay = document.getElementById('cp-nav-overlay');
    if(!btn || !nav) return;
    var lockedScrollY = 0;

    function open(){
      lockedScrollY = window.scrollY || window.pageYOffset || 0;
      document.body.style.top = (-lockedScrollY) + 'px';
      document.body.classList.add('cp-scroll-lock');
    }
    function close(){
      nav.classList.remove('cp-open');
      if(overlay){ overlay.classList.remove('cp-open'); }
      btn.setAttribute('aria-expanded','false');
      document.body.classList.remove('cp-scroll-lock');
      document.body.style.top = '';
      window.scrollTo(0, lockedScrollY);
    }
    btn.addEventListener('click', function(){
      var opened = nav.classList.toggle('cp-open');
      if(overlay){ overlay.classList.toggle('cp-open', opened); }
      btn.setAttribute('aria-expanded', opened ? 'true':'false');
      if(opened){ open(); }
      else { close(); }
    });
    if(overlay){ overlay.addEventListener('click', close); }

    var subToggles = nav.querySelectorAll('.cp-has-sub > a');
    for(var i=0;i<subToggles.length;i++){
      subToggles[i].addEventListener('click', function(e){
        if(window.innerWidth <= 980){
          var parent = this.parentElement;
          if(parent.querySelector('.cp-sub-menu')){
            e.preventDefault();
            parent.classList.toggle('cp-mobile-open');
          }
        }
      });
    }
  }

  /* ---------------------------------------------------------
     2. 검색 패널
  --------------------------------------------------------- */
  function initSearchPanel(){
    var openBtn = document.getElementById('cp-search-open');
    var panel = document.getElementById('cp-search-panel');
    var closeBtn = document.getElementById('cp-search-close');
    if(!openBtn || !panel) return;
    var lockedScrollY = 0;
    openBtn.addEventListener('click', function(){
      lockedScrollY = window.scrollY || window.pageYOffset || 0;
      document.body.style.top = (-lockedScrollY) + 'px';
      panel.classList.add('cp-open');
      document.body.classList.add('cp-scroll-lock');
      var input = panel.querySelector('input[type="text"]');
      if(input){ setTimeout(function(){ input.focus(); }, 50); }
    });
    function close(){
      panel.classList.remove('cp-open');
      document.body.classList.remove('cp-scroll-lock');
      document.body.style.top = '';
      window.scrollTo(0, lockedScrollY);
    }
    if(closeBtn){ closeBtn.addEventListener('click', close); }
    panel.addEventListener('click', function(e){ if(e.target === panel){ close(); } });
    document.addEventListener('keydown', function(e){ if(e.key === 'Escape'){ close(); } });
  }

  /* ---------------------------------------------------------
     3. 자동 썸네일 생성 (SVG) - 사용자가 이미지 삽입 안했을 때만
     가독성/클릭률 고려: 대비 높은 배경 + 큰 타이포 + 브랜드 톤
  --------------------------------------------------------- */
  var THUMB_PALETTES = [
    ['#2457C5','#173d94'],
    ['#1d2129','#3a4152'],
    ['#0f766e','#0a4f4a'],
    ['#b45309','#7c3609'],
    ['#7c3aed','#5b21b6'],
    ['#be123c','#881337']
  ];

  function hashStr(str){
    var h = 0;
    for(var i=0;i<str.length;i++){ h = (h << 5) - h + str.charCodeAt(i); h |= 0; }
    return Math.abs(h);
  }

  function wrapTitleLines(title, maxCharsPerLine){
    var words = title.split(' ');
    var lines = [];
    var current = '';
    for(var i=0;i<words.length;i++){
      var test = current ? current + ' ' + words[i] : words[i];
      if(test.length > maxCharsPerLine && current){
        lines.push(current);
        current = words[i];
      } else {
        current = test;
      }
    }
    if(current) lines.push(current);
    if(lines.length > 3){
      lines = lines.slice(0,3);
      lines[2] = lines[2].length > maxCharsPerLine - 1 ? lines[2].slice(0, maxCharsPerLine - 1) + '\u2026' : lines[2] + '\u2026';
    }
    return lines;
  }

  function escapeXml(str){
    return String(str).replace(/[<>&'"]/g, function(c){
      return ({'<':'&lt;','>':'&gt;','&':'&amp;',"'":'&apos;','"':'&quot;'})[c];
    });
  }

  /* Blogger 피드 썸네일(기본 72x72 저화질)을 고화질 URL로 변환.
     Blogger/Google 이미지 URL은 크기 지정자가 여러 형태로 올 수 있다:
     - 접미사형(신형): ...xxx=s72-c, ...xxx=w72-h72-n-o, ...xxx=s72-c-rw
     - 경로형(구형): .../s72-c/..., .../w72-h72/...
     ?imgmax=800 같은 쿼리스트링이 붙어 매칭이 실패하는 것을 막기 위해 먼저 제거하고,
     s/w/h 크기 지정자를 폭넓게 인식하는 정규식으로 원하는 해상도로 교체한다. */
  function upgradeThumbUrl(url, w, h){
    if(!url) return '';
    var base = url.split('?')[0];
    var sizeTag = '=w' + w + '-h' + h + '-p-k-no-nu';

    var suffixRe = /=((?:[swh]\d+-?)+[a-z0-9-]*)$/i;
    if(suffixRe.test(base)){
      return base.replace(suffixRe, sizeTag);
    }
    var pathRe = /\/((?:[swh]\d+-?)+[a-z0-9-]*)\//i;
    if(pathRe.test(base)){
      return base.replace(pathRe, '/w' + w + '-h' + h + '-p-k-no-nu/');
    }
    // 크기 지정자를 못 찾았고 Google 이미지 CDN이면 접미사로 강제 추가
    if(/googleusercontent\.com/i.test(base)){
      return base + sizeTag;
    }
    return base;
  }

  function buildThumbSvg(title, w, h){
    var idx = hashStr(title) % THUMB_PALETTES.length;
    var colors = THUMB_PALETTES[idx];
    var lines = wrapTitleLines(title, w > 700 ? 16 : 12);
    var fontSize = w > 700 ? 46 : 26;
    var lineHeight = fontSize * 1.32;
    var totalH = lines.length * lineHeight;
    var startY = h/2 - totalH/2 + fontSize*0.78;

    var tspans = '';
    for(var i=0;i<lines.length;i++){
      tspans += '<text x="' + (w*0.08) + '" y="' + (startY + i*lineHeight) + '" font-family="\'Noto Sans KR\',sans-serif" font-weight="900" font-size="' + fontSize + '" fill="#ffffff" xml:space="preserve">' + escapeXml(lines[i]) + '</text>';
    }

    var svg = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ' + w + ' ' + h + '" width="' + w + '" height="' + h + '" role="img" aria-label="' + escapeXml(title) + '">' +
      '<defs><linearGradient id="g' + idx + '" x1="0%" y1="0%" x2="100%" y2="100%">' +
      '<stop offset="0%" stop-color="' + colors[0] + '"/><stop offset="100%" stop-color="' + colors[1] + '"/>' +
      '</linearGradient></defs>' +
      '<rect width="' + w + '" height="' + h + '" fill="url(#g' + idx + ')"/>' +
      '<circle cx="' + (w*0.92) + '" cy="' + (h*0.14) + '" r="' + (w*0.22) + '" fill="#ffffff" opacity="0.06"/>' +
      '<circle cx="' + (w*0.06) + '" cy="' + (h*0.95) + '" r="' + (w*0.14) + '" fill="#ffffff" opacity="0.06"/>' +
      tspans +
      '<rect x="' + (w*0.08) + '" y="' + (h*0.86) + '" width="' + (w*0.12) + '" height="4" fill="#ffffff" opacity="0.85"/>' +
      '</svg>';

    return 'data:image/svg+xml;charset=UTF-8,' + encodeURIComponent(svg);
  }

  function initAutoThumbnails(){
    var nodes = document.querySelectorAll('.cp-auto-thumb, .cp-auto-thumb-lg');
    for(var i=0;i<nodes.length;i++){
      var el = nodes[i];
      var title = el.getAttribute('data-title') || document.title;
      var isLarge = el.classList.contains('cp-auto-thumb-lg');
      var w = isLarge ? 1200 : 480;
      var h = isLarge ? 675 : 300;
      var uri = buildThumbSvg(title, w, h);

      if(el.tagName === 'FIGURE'){
        var existingImg = el.querySelector('img');
        if(existingImg){
          existingImg.src = uri;
          existingImg.style.opacity = '1';
        } else {
          var img = document.createElement('img');
          img.src = uri;
          img.alt = title;
          img.loading = 'lazy';
          el.appendChild(img);
        }
      } else {
        el.style.backgroundImage = 'url(' + uri + ')';
        el.style.backgroundSize = 'cover';
        el.style.backgroundPosition = 'center';
        el.classList.add('cp-thumb-ready');
        // 내부에 실제 <img> 엘리먼트가 있으면(검색엔진 크롤링/이미지 검색 노출용)
        // 그 이미지의 src도 동일한 SVG로 채워 실체가 있는 <img alt="..."> 형태로 만든다.
        var innerImg = el.querySelector('img');
        if(innerImg){
          innerImg.src = uri;
          innerImg.style.opacity = '1';
        }
      }
    }
  }

  /* ---------------------------------------------------------
     4. 본문 굵은 텍스트 링크 자동 버튼화
     - <p> 안에 <b><a> 또는 <strong><a> 또는 볼드 처리된 단일 링크만 있는 경우 버튼 스타일 적용
  --------------------------------------------------------- */
  function initAutoCtaButtons(){
    var body = document.getElementById('cp-post-body');
    if(!body) return;
    var paragraphs = body.querySelectorAll('p');
    for(var i=0;i<paragraphs.length;i++){
      var p = paragraphs[i];
      var text = p.textContent.trim();
      if(!text) continue;

      var directLink = null;
      if(p.children.length === 1 && p.children[0].tagName === 'A'){
        var parentStyle = window.getComputedStyle(p.children[0]);
        var weight = parseInt(parentStyle.fontWeight, 10) || 400;
        var isBoldWrap = p.innerHTML.match(/^<(b|strong)>\s*<a[\s\S]*<\/a>\s*<\/(b|strong)>$/i);
        if(isBoldWrap || weight >= 700){
          directLink = p.children[0];
        }
      } else if(p.children.length === 1 && (p.children[0].tagName === 'B' || p.children[0].tagName === 'STRONG')){
        var inner = p.children[0];
        if(inner.children.length === 1 && inner.children[0].tagName === 'A'){
          directLink = inner.children[0];
        }
      }

      if(directLink && directLink.textContent.trim().length > 0 && directLink.textContent.trim().length < 40){
        directLink.classList.add('cp-cta-btn');
        p.classList.add('cp-cta-btn-wrap');
      }
    }
  }

  /* ---------------------------------------------------------
     5. 자동 목차 생성 (h2, h3 기반) - 읽기시간/진행도 요소 없음
  --------------------------------------------------------- */
  function initAutoTOC(){
    var body = document.getElementById('cp-post-body');
    var tocWrap = document.getElementById('cp-toc');
    var tocList = document.getElementById('cp-toc-list');
    var tocHead = document.getElementById('cp-toc-head');
    if(!body || !tocWrap || !tocList) return;

    var headings = body.querySelectorAll('h2, h3');
    if(headings.length < 2){
      tocWrap.style.display = 'none';
      return;
    }

    var usedIds = {};
    var frag = document.createDocumentFragment();

    for(var i=0;i<headings.length;i++){
      var h = headings[i];
      var baseId = 'cp-h-' + i + '-' + h.textContent.trim().replace(/[^\w\uAC00-\uD7A3]+/g,'-').replace(/^-+|-+$/g,'').slice(0,40);
      if(!baseId || baseId === 'cp-h-' + i + '-'){ baseId = 'cp-h-' + i; }
      var id = baseId;
      var n = 1;
      while(usedIds[id]){ id = baseId + '-' + n; n++; }
      usedIds[id] = true;
      h.id = id;

      var li = document.createElement('li');
      if(h.tagName === 'H3'){ li.className = 'cp-toc-lv3'; }
      var a = document.createElement('a');
      a.href = '#' + id;
      a.textContent = h.textContent.trim();
      li.appendChild(a);
      frag.appendChild(li);
    }
    tocList.appendChild(frag);

    if(tocHead){
      tocHead.addEventListener('click', function(){
        tocWrap.classList.toggle('cp-collapsed');
      });
    }

    var links = tocList.querySelectorAll('a');
    for(var j=0;j<links.length;j++){
      links[j].addEventListener('click', function(e){
        e.preventDefault();
        var target = document.getElementById(this.getAttribute('href').slice(1));
        if(target){
          var y = target.getBoundingClientRect().top + window.pageYOffset - 80;
          window.scrollTo({top:y, behavior:'smooth'});
          history.replaceState(null, '', '#' + target.id);
        }
      });
    }
  }

  /* ---------------------------------------------------------
     6. FAQ 아코디언 (본문 내 .cp-faq 구조 지원) + FAQPage 구조화 데이터 자동 주입
  --------------------------------------------------------- */
  function initFaqAccordion(){
    var questions = document.querySelectorAll('.cp-faq-q');
    for(var i=0;i<questions.length;i++){
      questions[i].addEventListener('click', function(){
        var item = this.parentElement;
        var wasOpen = item.classList.contains('cp-open');
        var siblings = item.parentElement.querySelectorAll('.cp-faq-item');
        for(var j=0;j<siblings.length;j++){ siblings[j].classList.remove('cp-open'); }
        if(!wasOpen){ item.classList.add('cp-open'); }
      });
    }
    injectFaqSchema();
  }

  function injectFaqSchema(){
    var body = document.getElementById('cp-post-body');
    if(!body) return;
    var items = body.querySelectorAll('.cp-faq-item');
    if(items.length === 0) return;

    var faqEntities = [];
    for(var i=0;i<items.length;i++){
      var qEl = items[i].querySelector('.cp-faq-q');
      var aEl = items[i].querySelector('.cp-faq-a-inner') || items[i].querySelector('.cp-faq-a');
      if(!qEl || !aEl) continue;
      var qText = qEl.textContent.replace(/\s+/g,' ').trim();
      var aText = aEl.textContent.replace(/\s+/g,' ').trim();
      if(!qText || !aText) continue;
      faqEntities.push({
        "@type":"Question",
        "name": qText,
        "acceptedAnswer": { "@type":"Answer", "text": aText }
      });
    }
    if(faqEntities.length === 0) return;

    var schema = {
      "@context":"https://schema.org",
      "@type":"FAQPage",
      "mainEntity": faqEntities
    };
    var script = document.createElement('script');
    script.type = 'application/ld+json';
    script.text = JSON.stringify(schema);
    document.head.appendChild(script);
  }

  /* ---------------------------------------------------------
     7. 단일 공유 버튼 (기기 Web Share API 우선, 미지원 시 클립보드 복사)
--------------------------------------------------------- */
  function initShareButton(){
    var btn = document.getElementById('cp-share-btn');
    var toast = document.getElementById('cp-share-toast');
    if(!btn) return;

    btn.addEventListener('click', function(){
      var url = btn.getAttribute('data-share-url') || window.location.href;
      var title = btn.getAttribute('data-share-title') || document.title;

      if(navigator.share){
        navigator.share({ title: title, url: url }).catch(function(){});
      } else if(navigator.clipboard && navigator.clipboard.writeText){
        navigator.clipboard.writeText(url).then(function(){
          showToast();
        }).catch(function(){
          legacyCopy(url);
          showToast();
        });
      } else {
        legacyCopy(url);
        showToast();
      }
    });

    function legacyCopy(text){
      var ta = document.createElement('textarea');
      ta.value = text;
      ta.style.position = 'fixed';
      ta.style.opacity = '0';
      document.body.appendChild(ta);
      ta.select();
      try{ document.execCommand('copy'); }catch(e){}
      document.body.removeChild(ta);
    }

    function showToast(){
      if(!toast) return;
      toast.classList.add('cp-show');
      setTimeout(function(){ toast.classList.remove('cp-show'); }, 2200);
    }
  }

  /* ---------------------------------------------------------
     8. 맨 위로 버튼
  --------------------------------------------------------- */
  function initBackToTop(){
    var btn = document.getElementById('cp-back-to-top');
    if(!btn) return;
    window.addEventListener('scroll', function(){
      if(window.pageYOffset > 500){ btn.classList.add('cp-show'); }
      else { btn.classList.remove('cp-show'); }
    }, {passive:true});
    btn.addEventListener('click', function(){
      window.scrollTo({top:0, behavior:'smooth'});
    });
  }

  /* ---------------------------------------------------------
     9. 모바일 고정 광고 닫기
  --------------------------------------------------------- */
  function initStickyAdClose(){
    var wrap = document.querySelector('.cp-sticky-ad-mobile');
    if(!wrap) return;
    var closeEl = document.createElement('div');
    closeEl.className = 'cp-sticky-ad-close';
    closeEl.textContent = '\u2715';
    closeEl.setAttribute('role','button');
    closeEl.setAttribute('aria-label','광고 닫기');
    closeEl.addEventListener('click', function(){ wrap.style.display = 'none'; });
    wrap.appendChild(closeEl);
  }

  /* ---------------------------------------------------------
     10. 자동 관련 글 추천 (같은 라벨의 최신 글 중 현재 글 제외, JSONP)
  --------------------------------------------------------- */
  function initRelatedPosts(){
    var wrap = document.getElementById('cp-related-wrap');
    var grid = document.getElementById('cp-related-grid');
    if(!wrap || !grid) return;
    var currentId = wrap.getAttribute('data-post-id');
    var labelLinks = wrap.querySelectorAll('a.cp-related-label-src');
    if(labelLinks.length === 0){ wrap.style.display = 'none'; return; }

    var collected = [];
    var seen = {};
    var pending = 0;
    var cbIndex = 0;
    var validFeeds = [];

    for(var i=0;i<labelLinks.length;i++){
      var rawHref = labelLinks[i].getAttribute('href');
      var feedUrl = rawHref.replace(/\/search\/label\/([^?]+).*$/, '/feeds/posts/default/-/$1') + '?alt=json-in-script&max-results=8&callback=?';
      feedUrl = feedUrl.replace(/^http:\/\//, 'https://');
      if(feedUrl.indexOf('/feeds/posts/default/-/') !== -1){ validFeeds.push(feedUrl); }
    }
    if(validFeeds.length === 0){ wrap.style.display = 'none'; return; }
    pending = validFeeds.length;
    for(var j=0;j<validFeeds.length;j++){
      loadFeed(validFeeds[j]);
    }

    function loadFeed(url){
      var cbName = 'cpRelatedCb' + (cbIndex++) + '_' + Date.now();
      window[cbName] = function(json){
        try{
          var entries = (json.feed && json.feed.entry) || [];
          for(var e=0;e<entries.length;e++){
            var entry = entries[e];
            var idParts = entry.id.$t.split('post-');
            var postId = idParts[idParts.length-1];
            if(postId === currentId || seen[postId]) continue;
            seen[postId] = true;

            var link = '';
            for(var l=0;l<entry.link.length;l++){
              if(entry.link[l].rel === 'alternate'){ link = entry.link[l].href; break; }
            }
            if(!link) continue;

            var thumb = entry.media$thumbnail ? upgradeThumbUrl(entry.media$thumbnail.url, 400, 225) : '';
            collected.push({
              title: entry.title.$t,
              url: link,
              thumb: thumb
            });
          }
        }catch(err){}
        pending--;
        if(pending <= 0){ renderRelated(); }
        try{ delete window[cbName]; }catch(err2){ window[cbName] = undefined; }
        var s = document.getElementById(cbName + '_script');
        if(s){ s.parentNode.removeChild(s); }
      };
      var callbackUrl = url.replace('callback=?', 'callback=' + cbName);
      var script = document.createElement('script');
      script.id = cbName + '_script';
      script.setAttribute('data-cfasync', 'false');
      script.src = callbackUrl;
      script.onerror = function(){
        pending--;
        if(pending <= 0){ renderRelated(); }
      };
      document.body.appendChild(script);
    }

    function renderRelated(){
      if(collected.length === 0){
        wrap.style.display = 'none';
        return;
      }
      var shuffled = collected.slice(0, 12);
      var picked = shuffled.slice(0, 6);
      var html = '';
      for(var i=0;i<picked.length;i++){
        var p = picked[i];
        var safeTitleAttr = escapeXml(p.title);
        var thumbHtml;
        if(p.thumb){
          thumbHtml = '<img src="' + p.thumb + '" alt="' + safeTitleAttr + '" loading="lazy" onerror="this.onerror=null;this.parentNode.innerHTML=window.__cpBuildRelatedFallback(' + JSON.stringify(p.title) + ');"/>';
        } else {
          thumbHtml = window.__cpBuildRelatedFallback(p.title);
        }
        html += '<a class="cp-related-card" href="' + p.url + '">' +
                  '<div class="cp-related-thumb">' + thumbHtml + '</div>' +
                  '<div class="cp-related-body"><div class="cp-related-title">' + safeTitleAttr + '</div></div>' +
                '</a>';
      }
      grid.innerHTML = html;
    }
  }

  /* 관련 글 썸네일 로드 실패(onerror) 시 즉시 호출되는 폴백 - buildThumbSvg를 인라인 <img>로 반환 */
  window.__cpBuildRelatedFallback = function(title){
    try{
      var uri = buildThumbSvg(title, 400, 225);
      return '<img src="' + uri + '" alt="' + escapeXml(title).replace(/"/g,'&quot;') + '" loading="lazy"/>';
    }catch(e){
      return '';
    }
  };

  /* ---------------------------------------------------------
     사이드바 "최신 글" 위젯 - 블로그 자체 피드에서 로드
  --------------------------------------------------------- */
  /* 범용: 지정된 wrap/list 요소에 Blogger 피드 기반 글 목록을 렌더링.
     showRank가 true면 순번(1,2,3..)을 붙이고 날짜는 생략(인기글용).
     false면 날짜를 붙이고 순번은 생략(최신글용). */
  function loadPostListFromFeed(wrapId, listId, feedUrl, showRank){
    var wrap = document.getElementById(wrapId);
    var list = document.getElementById(listId);
    if(!wrap || !list || !feedUrl) return;
    feedUrl = feedUrl.replace(/^http:\/\//, 'https://');

    var cbName = 'cpFeedCb_' + Date.now() + '_' + Math.floor(Math.random()*10000);
    window[cbName] = function(json){
      try{
        var entries = (json.feed && json.feed.entry) || [];
        var html = '';
        for(var i=0;i<entries.length;i++){
          var entry = entries[i];
          var link = '';
          for(var l=0;l<entry.link.length;l++){
            if(entry.link[l].rel === 'alternate'){ link = entry.link[l].href; break; }
          }
          if(!link) continue;
          var title = entry.title.$t;
          var thumb = entry.media$thumbnail ? upgradeThumbUrl(entry.media$thumbnail.url, showRank ? 120 : 120, 120) : '';
          var dateStr = '';
          if(!showRank){
            try{
              var d = new Date(entry.published.$t);
              dateStr = d.getFullYear() + '.' + (d.getMonth()+1) + '.' + d.getDate();
            }catch(errDate){}
          }
          var rankHtml = showRank ? '<span class="cp-mini-rank">' + (i+1) + '</span>' : '';
          var titleAttr = escapeXml(title);
          var thumbInner = thumb
            ? '<img src="' + thumb + '" alt="' + titleAttr + '" loading="lazy" onerror="this.onerror=null;this.parentNode.innerHTML=window.__cpBuildRelatedFallback(' + JSON.stringify(title) + ');"/>'
            : window.__cpBuildRelatedFallback(title);
          var thumbHtml = '<span class="cp-mini-thumb">' + thumbInner + '</span>';
          html += '<li><a class="cp-mini-post" href="' + link + '">' +
                    rankHtml + thumbHtml +
                    '<span class="cp-mini-info"><span class="cp-mini-title">' + titleAttr + '</span>' +
                    (dateStr ? '<span class="cp-mini-date">' + dateStr + '</span>' : '') +
                    '</span></a></li>';
        }
        if(html){ list.innerHTML = html; }
        else if(!list.children.length){ wrap.style.display = 'none'; }
      }catch(err){
        if(!list.children.length){ wrap.style.display = 'none'; }
      }
      try{ delete window[cbName]; }catch(err2){ window[cbName] = undefined; }
      var s = document.getElementById(cbName + '_script');
      if(s){ s.parentNode.removeChild(s); }
    };
    var callbackUrl = feedUrl.replace('callback=?', 'callback=' + cbName);
    var script = document.createElement('script');
    script.id = cbName + '_script';
    script.setAttribute('data-cfasync', 'false');
    script.src = callbackUrl;
    script.onerror = function(){ if(!list.children.length){ wrap.style.display = 'none'; } };
    document.body.appendChild(script);
  }

  function initRecentPosts(){
    var wrap = document.getElementById('cp-recent-posts');
    if(!wrap) return;
    var feedUrl = wrap.getAttribute('data-feed-url');
    loadPostListFromFeed('cp-recent-posts', 'cp-recent-posts-list', feedUrl, false);
  }

  /* 인기글(PopularPosts)은 Blogger 조회수 통계 기반이라 통계가 부족하면
     data:posts가 비어 목록이 렌더링되지 않는다. 목록이 비어 있으면
     블로그 자체 최신글 피드로 자동 대체한다. */
  function initPopularPostsFallback(){
    var wrap = document.getElementById('cp-popular-posts');
    var list = document.getElementById('cp-popular-posts-list');
    if(!wrap || !list) return;
    if(list.children.length > 0) return;
    var feedUrl = (window.location.protocol + '//' + window.location.host + '/feeds/posts/default?alt=json-in-script&max-results=5&orderby=published&callback=?');
    loadPostListFromFeed('cp-popular-posts', 'cp-popular-posts-list', feedUrl, true);
  }

})();
